// frontend/src/pages/UserStore.tsx
import React, { useEffect, useState } from 'react';
import { bookService, orderService } from '../services/api';
import { Book } from '../types';
import BookCard from '../components/BookCard';

const UserStore = () => {
  const [books, setBooks] = useState<Book[]>([]);
  const [cart, setCart] = useState<Book[]>([]);

  const fetchBooks = async () => {
    try {
      const { data } = await bookService.getAll();
      setBooks(data);
    } catch (error) {
      console.error("Kitaplar yüklenemedi");
    }
  };

  useEffect(() => { fetchBooks(); }, []);

  const addToCart = (book: Book) => {
    setCart([...cart, book]);
  };

  const removeFromCart = (index: number) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };

  const handleCheckout = async () => {
    if (cart.length === 0) return alert("Sepetiniz boş!");
    const total = cart.reduce((sum, item) => sum + item.price, 0);

    try {
      await orderService.placeOrder(total);
      alert(`Toplam ₺${total} tutarındaki ${cart.length} adet kitap satın alındı!`);
      setCart([]);
    } catch (error) {
      alert("Satın alma hatası");
    }
  };

  return (
    <div className="max-w-7xl mx-auto p-6">
      <div className="flex flex-col lg:flex-row gap-8">

        {/* SOL TARAF: Kitap Listesi */}
        <div className="flex-[3]">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-3xl font-black text-slate-800 tracking-tight">Kitap Mağazası</h2>
            <p className="text-slate-500 font-medium bg-slate-100 px-4 py-1 rounded-full text-sm">
              {books.length} Kitap Listeleniyor
            </p>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-6">
            {books.map(book => (
              <BookCard 
                key={book.id} 
                book={book} 
                actionButton={
                  <button 
                    onClick={() => addToCart(book)} 
                    className="mt-4 w-full py-3 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-lg shadow-blue-200 transition-all active:scale-95 flex items-center justify-center gap-2"
                  >
                    <span>Sepete Ekle</span>
                    <span className="text-lg">+</span>
                  </button>
                }
              />
            ))}
          </div>
        </div>

        {/* SAĞ TARAF: Sepet Paneli (Sticky - Sayfayla beraber kayar) */}
        <div className="flex-[1] lg:relative">
          <div className="sticky top-6 bg-white p-6 rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 space-y-6">
            <div className="flex items-center justify-between border-b border-slate-100 pb-4">
              <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <span>🛒</span> Sepetim
              </h3>
              <span className="bg-blue-100 text-blue-600 text-xs font-black px-2.5 py-1 rounded-lg">
                {cart.length}
              </span>
            </div>

            {/* Sepet Ürün Listesi */}
            <div className="max-h-[400px] overflow-y-auto space-y-3 pr-2 scrollbar-thin scrollbar-thumb-slate-200">
              {cart.length === 0 ? (
                <div className="text-center py-8">
                  <p className="text-slate-400 text-sm italic">Sepetin şu an boş...</p>
                </div>
              ) : (
                cart.map((item, index) => (
                  <div key={index} className="flex items-center justify-between group animate-fadeIn">
                    <div className="flex flex-col">
                      <span className="text-sm font-bold text-slate-700 truncate max-w-[120px]">{item.title}</span>
                      <span className="text-xs text-slate-400">₺{item.price}</span>
                    </div>
                    <button 
                      onClick={() => removeFromCart(index)} 
                      className="w-8 h-8 flex items-center justify-center text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-full transition-all"
                    >
                      ✕
                    </button>
                  </div>
                ))
              )}
            </div>

            {/* Toplam Bilgisi */}
            <div className="pt-4 border-t border-slate-100 space-y-4">
              <div className="flex justify-between items-end">
                <span className="text-sm font-medium text-slate-500">Genel Toplam</span>
                <span className="text-2xl font-black text-slate-800">
                  ₺{cart.reduce((sum, item) => sum + item.price, 0)}
                </span>
              </div>

              <button 
                onClick={handleCheckout}
                disabled={cart.length === 0}
                className={`w-full py-4 rounded-2xl font-black transition-all shadow-xl active:scale-[0.98] ${
                  cart.length > 0 
                  ? 'bg-emerald-500 hover:bg-emerald-600 text-white shadow-emerald-200' 
                  : 'bg-slate-100 text-slate-400 cursor-not-allowed shadow-none'
                }`}
              >
                Satın Almayı Tamamla
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default UserStore;
